const body = $input.first().json.body || $input.first().json;
if (!body.client_id) throw new Error('Missing required field: client_id');
return [{ json: { client_id: body.client_id, pipeline_run_id: body.pipeline_run_id || null, started_at: new Date().toISOString() } }];

// Run Tier 0a (regex negatives) and Tier 0b (competitor brand filter) via Supabase RPC
// These are Postgres functions that return keyword IDs grouped by decision
const client = ($input.first().json || [])[0];
const ctx = $('Validate_Filter_Payload').first().json;
if (!client) throw new Error('Client not found: ' + ctx.client_id);
return [{ json: { ...ctx, client_id: client.id, client_config: client.config, client_slug: client.slug } }];

// Tier 1: embed each unclassified keyword and compute cosine similarity vs gold_example centroids
// Returns items with tier1_decision: passed | rejected | borderline
const ctx = $('Merge_Client_Config').first().json;
const keywords = $('Fetch_Unclassified_Keywords').first().json || [];
const goldExamples = $('Fetch_Gold_Examples').first().json || [];

const positives = goldExamples.filter(g => g.label === 'positive' && g.embedding);
const negatives = goldExamples.filter(g => g.label === 'negative' && g.embedding);

// Helper: cosine similarity
function cosine(a, b) {
  if (!a || !b || a.length !== b.length) return 0;
  let dot = 0, na = 0, nb = 0;
  for (let i = 0; i < a.length; i++) { dot += a[i]*b[i]; na += a[i]*a[i]; nb += b[i]*b[i]; }
  return na && nb ? dot / (Math.sqrt(na) * Math.sqrt(nb)) : 0;
}

// Centroid: average of embeddings
function centroid(vecs) {
  if (!vecs.length) return null;
  const len = vecs[0].length;
  const c = new Array(len).fill(0);
  for (const v of vecs) for (let i = 0; i < len; i++) c[i] += v[i];
  return c.map(v => v / vecs.length);
}

const posCentroid = centroid(positives.map(g => g.embedding));
const negCentroid = centroid(negatives.map(g => g.embedding));

// Return keywords that need embedding (we batch-embed then re-enter this logic)
// For now, mark all as needing_tier1_embedding — WF-02 Part 2 handles embedding + scoring
return [{
  json: {
    ...ctx,
    keywords_to_embed: keywords.map(k => k.keyword),
    keyword_ids: keywords.map(k => k.id),
    has_gold_examples: positives.length > 0 || negatives.length > 0,
    pos_centroid: posCentroid,
    neg_centroid: negCentroid
  }
}];

// Score embeddings against gold centroids and assign tier1 decision
const ctx = $('Prepare_Tier1').first().json;
const embResp = $input.first().json;
const embeddings = embResp?.data || [];

function cosine(a, b) {
  if (!a || !b || a.length !== b.length) return 0;
  let dot = 0, na = 0, nb = 0;
  for (let i = 0; i < a.length; i++) { dot += a[i]*b[i]; na += a[i]*a[i]; nb += b[i]*b[i]; }
  return na && nb ? dot / (Math.sqrt(na) * Math.sqrt(nb)) : 0;
}

const results = embeddings.map((e, i) => {
  const kw = ctx.keywords_to_embed[i];
  const id = ctx.keyword_ids[i];
  const emb = e.embedding;
  const posScore = ctx.has_gold_examples ? cosine(emb, ctx.pos_centroid) : 0.5;
  const negScore = ctx.has_gold_examples ? cosine(emb, ctx.neg_centroid) : 0.5;
  const diff = posScore - negScore;
  let tier1_decision;
  if (diff > 0.15) tier1_decision = 'passed';
  else if (diff < -0.15) tier1_decision = 'rejected';
  else tier1_decision = 'borderline';
  return { keyword: kw, raw_keyword_id: id, embedding: emb, pos_score: posScore, neg_score: negScore, tier1_decision };
});

const borderline = results.filter(r => r.tier1_decision === 'borderline');
const passed = results.filter(r => r.tier1_decision === 'passed');
const rejected = results.filter(r => r.tier1_decision === 'rejected');

return [{ json: { ...ctx, tier1_results: results, borderline, passed_tier1: passed, rejected_tier1: rejected, embed_tokens: embResp?.usage?.total_tokens || 0 } }];

// WAVE 2 FIX: Convert passed_tier1 and rejected_tier1 arrays to n8n items
// These will be written to keyword_classifications in parallel to the borderline/Tier2 path

const scoreResults = $input.first().json;
const clientContext = $('Fetch_Client_Config').first().json;

const classificationItems = [];

// Process passed keywords
for (const kw of (scoreResults.passed_tier1 || [])) {
  classificationItems.push({
    json: {
      raw_keyword_id: kw.raw_keyword_id,
      client_id: clientContext.id,
      pipeline_run_id: clientContext.pipeline_run_id,
      decided_by: 'tier1_embedding',
      status: 'passed',
      pos_score: kw.pos_score,
      neg_score: kw.neg_score,
      embedding: kw.embedding,
      scored_at: new Date().toISOString()
    }
  });
}

// Process rejected keywords
for (const kw of (scoreResults.rejected_tier1 || [])) {
  classificationItems.push({
    json: {
      raw_keyword_id: kw.raw_keyword_id,
      client_id: clientContext.id,
      pipeline_run_id: clientContext.pipeline_run_id,
      decided_by: 'tier1_embedding',
      status: 'rejected',
      pos_score: kw.pos_score,
      neg_score: kw.neg_score,
      embedding: kw.embedding,
      scored_at: new Date().toISOString()
    }
  });
}

// Return all items (n8n will fan out to N items)
return classificationItems.length > 0 
  ? classificationItems 
  : [{ json: { skip_write: true } }];

// Build Tier 2 LLM classify requests for borderline keywords
// Only send keywords where tier1_decision === 'borderline'
const ctx = $json;
const borderline = ctx.borderline || [];

return borderline.map(kw => ({
  json: {
    client_id: ctx.client_id,
    pipeline_run_id: ctx.pipeline_run_id,
    client_config: ctx.client_config,
    raw_keyword_id: kw.raw_keyword_id,
    keyword: kw.keyword,
    embedding: kw.embedding,
    tier1_pos_score: kw.pos_score,
    tier1_neg_score: kw.neg_score
  }
}));

// Parse Tier 2 response and write classification to Supabase
const ctx = $('Prep_Tier2_Items').item.json;
const llmRaw = $input.first().json;

let classification = {};
try {
  classification = JSON.parse(llmRaw.choices?.[0]?.message?.content || '{}');
} catch(e) {
  classification = { status: 'needs_review', confidence: 0, decision_reasoning: 'Parse error: ' + e.message };
}

const inputTokens = llmRaw.usage?.prompt_tokens || 0;
const outputTokens = llmRaw.usage?.completion_tokens || 0;

return [{
  json: {
    client_id: ctx.client_id,
    pipeline_run_id: ctx.pipeline_run_id,
    raw_keyword_id: ctx.raw_keyword_id,
    keyword: ctx.keyword,
    classification: {
      raw_keyword_id: ctx.raw_keyword_id,
      client_id: ctx.client_id,
      pipeline_run_id: ctx.pipeline_run_id,
      status: classification.status || 'needs_review',
      decided_by: 'tier2_llm',
      decision_reasoning: classification.decision_reasoning || '',
      confidence: classification.confidence || 0,
      intent_type: classification.intent_type || 'informational',
      niche_hint: classification.niche_hint || null,
      content_theme_hint: classification.content_theme_hint || null,
      icp_match_score: classification.icp_match_score || 0,
      llm_prompt_hash: 'tier2-classifier-v1'
    },
    llm_tokens: { input: inputTokens, output: outputTokens }
  }
}];
